import React, { useState, useCallback } from 'react';
import { Upload, AlertCircle, CheckCircle, Clock, Heart, Activity, FileText, ChevronDown, ChevronUp } from 'lucide-react';
import './App.css';

interface EcoResult {
  tem_estenose: boolean;
  gravidade: string;
  area_valvar: number | null;
  gradiente_medio: number | null;
  velocidade_maxima: number | null;
  prioridade: string;
  justificativa: string;
  indicacao_tavi: boolean;
  confianca: number;
}

interface LaudoProcessado {
  arquivo: string;
  timestamp: string;
  analise: EcoResult;
}

function App() {
  const [laudos, setLaudos] = useState<LaudoProcessado[]>([]);
  const [loading, setLoading] = useState(false);
  const [erro, setErro] = useState<string | null>(null);
  const [dragActive, setDragActive] = useState(false);
  const [expandedCard, setExpandedCard] = useState<number | null>(null);

  const processarLaudos = async (files: FileList | null) => {
    if (!files || files.length === 0) return;

    setLoading(true);
    setErro(null);

    const formData = new FormData();
    for (let i = 0; i < files.length; i++) {
      formData.append('arquivos', files[i]);
    }

    try {
      const response = await fetch('http://localhost:8000/processar-lote', {
        method: 'POST',
        body: formData
      });

      if (!response.ok) throw new Error(`Erro HTTP: ${response.status}`);

      const data = await response.json();
      setLaudos(data.laudos);
    } catch (error) {
      setErro(error instanceof Error ? error.message : 'Erro desconhecido');
    } finally {
      setLoading(false);
    }
  };

  const handleDrag = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    if (e.type === "dragenter" || e.type === "dragover") {
      setDragActive(true);
    } else if (e.type === "dragleave") {
      setDragActive(false);
    }
  }, []);

  const handleDrop = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setDragActive(false);
    if (e.dataTransfer.files && e.dataTransfer.files[0]) {
      processarLaudos(e.dataTransfer.files);
    }
  }, []);

  const stats = {
    total: laudos.length,
    alta: laudos.filter(l => l.analise.prioridade === 'alta').length,
    media: laudos.filter(l => l.analise.prioridade === 'media').length,
    baixa: laudos.filter(l => l.analise.prioridade === 'baixa').length,
  };

  const getPrioridadeColor = (p: string) => ({
    'alta': 'border-red-500 bg-red-50',
    'media': 'border-yellow-500 bg-yellow-50',
    'baixa': 'border-green-500 bg-green-50'
  }[p] || 'border-gray-500 bg-gray-50');

  const getPrioridadeIcon = (p: string) => ({
    'alta': <AlertCircle className="w-6 h-6 text-red-500" />,
    'media': <Clock className="w-6 h-6 text-amber-500" />,
    'baixa': <CheckCircle className="w-6 h-6 text-emerald-500" />
  }[p]);

  return (
    <div className="min-h-screen bg-slate-50">
      {/* Header */}
      <header className="bg-white border-b border-slate-200 sticky top-0 z-50 shadow-sm">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex items-center justify-between h-20">
            <img src="/logo.png" alt="CardioScreen" className="h-12 w-auto" />
            <div className="flex items-center gap-2 px-4 py-2 bg-emerald-50 rounded-full">
              <div className="w-2 h-2 bg-emerald-500 rounded-full animate-pulse"></div>
              <span className="text-sm text-emerald-700 font-medium">Online</span>
            </div>
          </div>
        </div>
      </header>

      {/* Hero Section */}
      <section className="relative overflow-hidden bg-gradient-to-br from-blue-900 via-blue-800 to-indigo-900">
        <div className="absolute inset-0 opacity-10">
          <div className="absolute inset-0" style={{backgroundImage: 'radial-gradient(circle at 2px 2px, white 1px, transparent 0)', backgroundSize: '32px 32px'}}></div>
        </div>
        <div className="relative max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-16 sm:py-20">
          <div className="text-center">
            <div className="inline-flex items-center gap-2 px-4 py-2 bg-white/10 backdrop-blur-sm rounded-full mb-6 border border-white/20">
              <Heart className="w-4 h-4 text-red-400" />
              <span className="text-sm text-white/90 font-medium">Triagem Inteligente com IA</span>
            </div>
            <h1 className="text-4xl sm:text-5xl lg:text-6xl font-bold text-white mb-4 tracking-tight">
              Análise de Laudos de
              <span className="block mt-2 text-transparent bg-clip-text bg-gradient-to-r from-red-400 via-red-300 to-orange-300">
                Ecocardiograma
              </span>
            </h1>
            <p className="text-lg sm:text-xl text-blue-100/80 max-w-2xl mx-auto">
              Identifique automaticamente pacientes com estenose aórtica candidatos a TAVI
            </p>
          </div>
        </div>
        <div className="absolute bottom-0 left-0 right-0 h-24 bg-gradient-to-t from-slate-50 to-transparent"></div>
      </section>

      {/* Main Content */}
      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 -mt-10 relative z-10 pb-16">

        {/* Upload Card */}
        <div className="bg-white rounded-2xl shadow-xl shadow-slate-200/50 border border-slate-200 overflow-hidden mb-8">
          <div className="p-6 sm:p-8">
            <div className="flex items-center gap-4 mb-6">
              <div className="p-3 bg-gradient-to-br from-blue-500 to-blue-600 rounded-xl shadow-lg shadow-blue-500/30">
                <Upload className="w-6 h-6 text-white" />
              </div>
              <div>
                <h2 className="text-xl font-bold text-slate-800">Upload de Laudos</h2>
                <p className="text-sm text-slate-500">Arraste PDFs ou clique para selecionar</p>
              </div>
            </div>

            <div 
              onDragEnter={handleDrag}
              onDragLeave={handleDrag}
              onDragOver={handleDrag}
              onDrop={handleDrop}
              className={`relative border-2 border-dashed rounded-xl transition-all duration-300 ${
                dragActive 
                  ? 'border-blue-500 bg-blue-50 scale-[1.02]' 
                  : 'border-slate-300 hover:border-blue-400 hover:bg-slate-50'
              }`}
            >
              <input
                type="file"
                multiple
                accept=".pdf"
                onChange={(e) => processarLaudos(e.target.files)}
                className="hidden"
                id="file-upload"
                disabled={loading}
              />
              <label htmlFor="file-upload" className="cursor-pointer block p-12 sm:p-16">
                <div className="flex flex-col items-center">
                  <div className={`p-4 rounded-full mb-4 transition-all duration-300 ${
                    dragActive ? 'bg-blue-100' : 'bg-slate-100'
                  }`}>
                    <FileText className={`w-12 h-12 transition-colors ${
                      dragActive ? 'text-blue-600' : 'text-slate-400'
                    }`} />
                  </div>
                  <span className="text-lg font-semibold text-slate-700 mb-1">
                    {dragActive ? 'Solte os arquivos aqui' : 'Clique ou arraste PDFs'}
                  </span>
                  <span className="text-sm text-slate-500">Suporta múltiplos arquivos</span>
                </div>
              </label>
            </div>

            {loading && (
              <div className="mt-6 p-5 bg-gradient-to-r from-blue-50 to-indigo-50 rounded-xl border border-blue-100">
                <div className="flex items-center gap-4">
                  <div className="relative">
                    <div className="w-10 h-10 border-4 border-blue-200 rounded-full"></div>
                    <div className="absolute top-0 left-0 w-10 h-10 border-4 border-blue-600 rounded-full border-t-transparent animate-spin"></div>
                  </div>
                  <div>
                    <p className="font-semibold text-blue-900">Processando com IA...</p>
                    <p className="text-sm text-blue-600">Analisando laudos com Claude Haiku</p>
                  </div>
                </div>
              </div>
            )}

            {erro && (
              <div className="mt-6 p-5 bg-red-50 border border-red-200 rounded-xl">
                <div className="flex items-center gap-3">
                  <div className="p-2 bg-red-100 rounded-lg">
                    <AlertCircle className="w-5 h-5 text-red-600" />
                  </div>
                  <div>
                    <p className="font-semibold text-red-800">Erro no processamento</p>
                    <p className="text-sm text-red-600">{erro}</p>
                  </div>
                </div>
              </div>
            )}
          </div>
        </div>

        {/* Stats Cards */}
        {laudos.length > 0 && (
          <div className="grid grid-cols-2 lg:grid-cols-4 gap-4 mb-8">
            <div className="bg-white rounded-xl p-5 border border-slate-200 shadow-sm">
              <div className="flex items-center gap-3">
                <div className="p-2 bg-slate-100 rounded-lg">
                  <Activity className="w-5 h-5 text-slate-600" />
                </div>
                <div>
                  <p className="text-2xl font-bold text-slate-800">{stats.total}</p>
                  <p className="text-sm text-slate-500">Total</p>
                </div>
              </div>
            </div>
            <div className="bg-white rounded-xl p-5 border border-red-200 shadow-sm">
              <div className="flex items-center gap-3">
                <div className="p-2 bg-red-100 rounded-lg">
                  <AlertCircle className="w-5 h-5 text-red-600" />
                </div>
                <div>
                  <p className="text-2xl font-bold text-red-600">{stats.alta}</p>
                  <p className="text-sm text-slate-500">Alta</p>
                </div>
              </div>
            </div>
            <div className="bg-white rounded-xl p-5 border border-amber-200 shadow-sm">
              <div className="flex items-center gap-3">
                <div className="p-2 bg-amber-100 rounded-lg">
                  <Clock className="w-5 h-5 text-amber-600" />
                </div>
                <div>
                  <p className="text-2xl font-bold text-amber-600">{stats.media}</p>
                  <p className="text-sm text-slate-500">Média</p>
                </div>
              </div>
            </div>
            <div className="bg-white rounded-xl p-5 border border-emerald-200 shadow-sm">
              <div className="flex items-center gap-3">
                <div className="p-2 bg-emerald-100 rounded-lg">
                  <CheckCircle className="w-5 h-5 text-emerald-600" />
                </div>
                <div>
                  <p className="text-2xl font-bold text-emerald-600">{stats.baixa}</p>
                  <p className="text-sm text-slate-500">Baixa</p>
                </div>
              </div>
            </div>
          </div>
        )}

        {/* Results */}
        {laudos.length > 0 && (
          <div className="bg-white rounded-2xl shadow-xl shadow-slate-200/50 border border-slate-200 overflow-hidden">
            <div className="p-6 sm:p-8 border-b border-slate-100">
              <h2 className="text-2xl font-bold text-slate-800">
                Resultados da Triagem
              </h2>
              <p className="text-slate-500 mt-1">
                {laudos.length} {laudos.length === 1 ? 'laudo analisado' : 'laudos analisados'}
              </p>
            </div>

            <div className="divide-y divide-slate-100">
              {laudos.map((laudo, i) => (
                <div 
                  key={i} 
                  className={`p-6 sm:p-8 transition-colors ${
                    laudo.analise.prioridade === 'alta' ? 'bg-red-50/50' :
                    laudo.analise.prioridade === 'media' ? 'bg-amber-50/50' : 'bg-emerald-50/30'
                  }`}
                >
                  <div className="flex items-start justify-between gap-4">
                    <div className="flex items-start gap-4 flex-1">
                      <div className={`p-3 rounded-xl ${
                        laudo.analise.prioridade === 'alta' ? 'bg-red-100' :
                        laudo.analise.prioridade === 'media' ? 'bg-amber-100' : 'bg-emerald-100'
                      }`}>
                        {getPrioridadeIcon(laudo.analise.prioridade)}
                      </div>
                      <div className="flex-1 min-w-0">
                        <div className="flex items-center gap-3 flex-wrap">
                          <h3 className="font-bold text-lg text-slate-800 truncate">{laudo.arquivo}</h3>
                          <span className={`px-3 py-1 rounded-full text-xs font-bold uppercase tracking-wide ${
                            laudo.analise.prioridade === 'alta' ? 'bg-red-500 text-white' :
                            laudo.analise.prioridade === 'media' ? 'bg-amber-500 text-white' :
                            'bg-emerald-500 text-white'
                          }`}>
                            {laudo.analise.prioridade}
                          </span>
                          {laudo.analise.indicacao_tavi && (
                            <span className="px-3 py-1 rounded-full text-xs font-bold bg-red-600 text-white flex items-center gap-1">
                              <Heart className="w-3 h-3" /> TAVI
                            </span>
                          )}
                        </div>
                        <p className="text-sm text-slate-500 mt-1">
                          {new Date(laudo.timestamp).toLocaleString('pt-BR')}
                        </p>
                      </div>
                    </div>
                    <button 
                      onClick={() => setExpandedCard(expandedCard === i ? null : i)}
                      className="p-2 hover:bg-slate-200/50 rounded-lg transition-colors"
                    >
                      {expandedCard === i ? (
                        <ChevronUp className="w-5 h-5 text-slate-400" />
                      ) : (
                        <ChevronDown className="w-5 h-5 text-slate-400" />
                      )}
                    </button>
                  </div>

                  {/* Metrics Grid */}
                  <div className="grid grid-cols-2 sm:grid-cols-4 gap-4 mt-6">
                    <div className="bg-white/80 rounded-xl p-4 border border-slate-200/50">
                      <p className="text-xs text-slate-500 uppercase tracking-wide font-medium">Gravidade</p>
                      <p className="text-lg font-bold text-slate-800 capitalize mt-1">{laudo.analise.gravidade}</p>
                    </div>
                    <div className="bg-white/80 rounded-xl p-4 border border-slate-200/50">
                      <p className="text-xs text-slate-500 uppercase tracking-wide font-medium">Área Valvar</p>
                      <p className="text-lg font-bold text-slate-800 mt-1">
                        {laudo.analise.area_valvar ? `${laudo.analise.area_valvar} cm²` : 'N/A'}
                      </p>
                    </div>
                    <div className="bg-white/80 rounded-xl p-4 border border-slate-200/50">
                      <p className="text-xs text-slate-500 uppercase tracking-wide font-medium">Gradiente</p>
                      <p className="text-lg font-bold text-slate-800 mt-1">
                        {laudo.analise.gradiente_medio ? `${laudo.analise.gradiente_medio} mmHg` : 'N/A'}
                      </p>
                    </div>
                    <div className="bg-white/80 rounded-xl p-4 border border-slate-200/50">
                      <p className="text-xs text-slate-500 uppercase tracking-wide font-medium">Velocidade</p>
                      <p className="text-lg font-bold text-slate-800 mt-1">
                        {laudo.analise.velocidade_maxima ? `${laudo.analise.velocidade_maxima} m/s` : 'N/A'}
                      </p>
                    </div>
                  </div>

                  {/* Expanded Content */}
                  {expandedCard === i && (
                    <div className="mt-6 p-5 bg-white/80 rounded-xl border border-slate-200/50">
                      <p className="text-xs text-slate-500 uppercase tracking-wide font-medium mb-2">Análise da IA</p>
                      <p className="text-slate-700 leading-relaxed">{laudo.analise.justificativa}</p>
                      <div className="flex items-center gap-4 mt-4 pt-4 border-t border-slate-200">
                        <span className="text-sm text-slate-500">
                          Confiança: <span className="font-semibold text-slate-700">{(laudo.analise.confianca * 100).toFixed(0)}%</span>
                        </span>
                        <button className="ml-auto px-5 py-2.5 bg-gradient-to-r from-blue-600 to-blue-700 text-white rounded-xl font-medium hover:from-blue-700 hover:to-blue-800 transition-all shadow-lg shadow-blue-500/30">
                          Revisar Laudo
                        </button>
                      </div>
                    </div>
                  )}
                </div>
              ))}
            </div>
          </div>
        )}
      </main>

      {/* Footer */}
      <footer className="bg-white border-t border-slate-200 py-8">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex flex-col sm:flex-row items-center justify-between gap-4">
            <div className="flex items-center gap-3">
              <img src="/logo.png" alt="CardioScreen" className="h-8 w-auto opacity-60" />
              <span className="text-sm text-slate-500">v1.0</span>
            </div>
            <p className="text-sm text-slate-500">
              Powered by <span className="font-medium text-slate-700">Claude Haiku</span> • Anthropic AI
            </p>
          </div>
        </div>
      </footer>
    </div>
  );
}

export default App;
